import{_ as s,o as a,c as n,a2 as l}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Open-Source and Local Models for Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/model-providers/open-source-models.md","filePath":"research/concepts/model-providers/open-source-models.md"}'),e={name:"research/concepts/model-providers/open-source-models.md"};function o(r,t,p,i,d,c){return a(),n("div",null,[...t[0]||(t[0]=[l(`<h1 id="open-source-and-local-models-for-coding-agents" tabindex="-1">Open-Source and Local Models for Coding Agents <a class="header-anchor" href="#open-source-and-local-models-for-coding-agents" aria-label="Permalink to &quot;Open-Source and Local Models for Coding Agents&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Open-source and locally-hosted models represent the privacy-first, cost-free alternative to cloud providers for CLI coding agents. While frontier cloud models (Claude, GPT-4, Gemini) dominate in raw capability, open-source models have reached a quality level where they are viable for many coding tasks—especially when self-hosted for zero marginal cost, unlimited rate limits, and complete data privacy.</p><p>Among the 17 agents studied, <strong>5 (29%)</strong> explicitly support local/open-source models, typically through Ollama or OpenAI-compatible API endpoints. Many more can use them through LiteLLM or custom endpoint configuration.</p><hr><h2 id="the-open-source-model-landscape-for-coding" tabindex="-1">The Open-Source Model Landscape for Coding <a class="header-anchor" href="#the-open-source-model-landscape-for-coding" aria-label="Permalink to &quot;The Open-Source Model Landscape for Coding&quot;">​</a></h2><h3 id="tier-1-frontier-open-models-70b" tabindex="-1">Tier 1: Frontier Open Models (70B+) <a class="header-anchor" href="#tier-1-frontier-open-models-70b" aria-label="Permalink to &quot;Tier 1: Frontier Open Models (70B+)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Parameters</th><th>Context</th><th>Coding Quality</th><th>License</th></tr></thead><tbody><tr><td><strong>Llama 3.1 405B</strong></td><td>405B</td><td>128K</td><td>Near GPT-4</td><td>Llama 3.1 License</td></tr><tr><td><strong>Llama 3.3 70B</strong></td><td>70B</td><td>128K</td><td>Strong</td><td>Llama 3.3 License</td></tr><tr><td><strong>Qwen2.5-Coder-32B</strong></td><td>32B</td><td>128K</td><td>Excellent (code-specialized)</td><td>Apache 2.0</td></tr><tr><td><strong>DeepSeek-R1-Distill-70B</strong></td><td>70B</td><td>128K</td><td>Very strong + reasoning</td><td>MIT</td></tr><tr><td><strong>Mistral Large</strong></td><td>~123B</td><td>128K</td><td>Strong</td><td>Mistral License</td></tr><tr><td><strong>CodeLlama 70B</strong></td><td>70B</td><td>100K</td><td>Good (code-specialized)</td><td>Llama 2 License</td></tr></tbody></table><h3 id="tier-2-efficient-models-7b-32b" tabindex="-1">Tier 2: Efficient Models (7B-32B) <a class="header-anchor" href="#tier-2-efficient-models-7b-32b" aria-label="Permalink to &quot;Tier 2: Efficient Models (7B-32B)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Parameters</th><th>Context</th><th>Coding Quality</th><th>License</th></tr></thead><tbody><tr><td><strong>Qwen2.5-Coder-7B</strong></td><td>7B</td><td>128K</td><td>Good for size</td><td>Apache 2.0</td></tr><tr><td><strong>Qwen2.5-Coder-14B</strong></td><td>14B</td><td>128K</td><td>Very good for size</td><td>Apache 2.0</td></tr><tr><td><strong>DeepSeek-R1-Distill-32B</strong></td><td>32B</td><td>128K</td><td>Excellent + reasoning</td><td>MIT</td></tr><tr><td><strong>CodeLlama 34B</strong></td><td>34B</td><td>100K</td><td>Good</td><td>Llama 2 License</td></tr><tr><td><strong>Mistral Nemo 12B</strong></td><td>12B</td><td>128K</td><td>Decent</td><td>Apache 2.0</td></tr><tr><td><strong>StarCoder2-15B</strong></td><td>15B</td><td>16K</td><td>Good (code-only)</td><td>BigCode License</td></tr><tr><td><strong>Llama 3.2 3B</strong></td><td>3B</td><td>128K</td><td>Basic</td><td>Llama 3.2 License</td></tr></tbody></table><h3 id="tier-3-tiny-models-7b" tabindex="-1">Tier 3: Tiny Models (&lt; 7B) <a class="header-anchor" href="#tier-3-tiny-models-7b" aria-label="Permalink to &quot;Tier 3: Tiny Models (&lt; 7B)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Parameters</th><th>Context</th><th>Coding Quality</th><th>License</th></tr></thead><tbody><tr><td><strong>Qwen2.5-Coder-1.5B</strong></td><td>1.5B</td><td>128K</td><td>Limited</td><td>Apache 2.0</td></tr><tr><td><strong>DeepSeek-R1-Distill-1.5B</strong></td><td>1.5B</td><td>128K</td><td>Limited + reasoning</td><td>MIT</td></tr><tr><td><strong>StarCoder2-3B</strong></td><td>3B</td><td>16K</td><td>Basic (code-only)</td><td>BigCode License</td></tr><tr><td><strong>TinyLlama</strong></td><td>1.1B</td><td>2K</td><td>Minimal</td><td>Apache 2.0</td></tr></tbody></table><hr><h2 id="key-model-families" tabindex="-1">Key Model Families <a class="header-anchor" href="#key-model-families" aria-label="Permalink to &quot;Key Model Families&quot;">​</a></h2><h3 id="llama-3-meta" tabindex="-1">Llama 3 (Meta) <a class="header-anchor" href="#llama-3-meta" aria-label="Permalink to &quot;Llama 3 (Meta)&quot;">​</a></h3><p>Meta&#39;s Llama 3 family is the most widely used open-source foundation model:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Available sizes</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> llama3.3:70b</span><span style="color:#6C7086;font-style:italic;">    # Best quality, needs ~45GB RAM</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> llama3.2:3b</span><span style="color:#6C7086;font-style:italic;">     # Smallest, runs on laptop</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> llama3.1:405b</span><span style="color:#6C7086;font-style:italic;">   # Largest, needs multi-GPU</span></span></code></pre></div><p><strong>Strengths:</strong></p><ul><li>Strong general-purpose coding ability</li><li>Large community and ecosystem</li><li>Available in multiple sizes (1B to 405B)</li><li>128K context window across all sizes</li><li>Good instruction following</li></ul><p><strong>Limitations:</strong></p><ul><li>Not specialized for code (general-purpose)</li><li>405B requires significant infrastructure</li><li>Function calling less reliable than specialized models</li></ul><h3 id="qwen2-5-coder-alibaba" tabindex="-1">Qwen2.5-Coder (Alibaba) <a class="header-anchor" href="#qwen2-5-coder-alibaba" aria-label="Permalink to &quot;Qwen2.5-Coder (Alibaba)&quot;">​</a></h3><p>The best open-source code-specialized model family:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Qwen2.5-Coder variants</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> qwen2.5-coder:32b</span><span style="color:#6C7086;font-style:italic;">  # Best quality, ~20GB RAM</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> qwen2.5-coder:14b</span><span style="color:#6C7086;font-style:italic;">  # Good balance, ~9GB RAM</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> qwen2.5-coder:7b</span><span style="color:#6C7086;font-style:italic;">   # Fast, ~5GB RAM</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> qwen2.5-coder:1.5b</span><span style="color:#6C7086;font-style:italic;"> # Tiny, ~1.5GB RAM</span></span></code></pre></div><p><strong>Strengths:</strong></p><ul><li><strong>Best-in-class coding</strong> for open models at each size</li><li>Trained specifically on code across 92 programming languages</li><li>128K context window</li><li>Apache 2.0 license (most permissive)</li><li>Outperforms many larger general-purpose models on coding tasks</li><li>Strong function calling support</li></ul><p><strong>Why Qwen2.5-Coder stands out:</strong></p><table tabindex="0"><thead><tr><th>Model</th><th>Size</th><th>HumanEval</th><th>MBPP</th><th>SWE-bench Lite</th></tr></thead><tbody><tr><td>Qwen2.5-Coder-32B</td><td>32B</td><td>92.7%</td><td>83.5%</td><td>~25%</td></tr><tr><td>CodeLlama-34B</td><td>34B</td><td>67.8%</td><td>72.6%</td><td>~15%</td></tr><tr><td>DeepSeek-Coder-33B</td><td>33B</td><td>79.3%</td><td>80.4%</td><td>~20%</td></tr><tr><td>Llama 3.1-70B</td><td>70B</td><td>80.5%</td><td>82.3%</td><td>~22%</td></tr></tbody></table><p>The 32B Qwen2.5-Coder matches or exceeds models 2x its size.</p><h3 id="codellama-meta" tabindex="-1">CodeLlama (Meta) <a class="header-anchor" href="#codellama-meta" aria-label="Permalink to &quot;CodeLlama (Meta)&quot;">​</a></h3><p>Meta&#39;s code-specialized variant of Llama 2:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> codellama:70b</span><span style="color:#6C7086;font-style:italic;">      # Best quality</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> codellama:34b</span><span style="color:#6C7086;font-style:italic;">      # Good balance</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> codellama:13b</span><span style="color:#6C7086;font-style:italic;">      # Lightweight</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> codellama:7b</span><span style="color:#6C7086;font-style:italic;">       # Fastest</span></span></code></pre></div><p><strong>Strengths:</strong></p><ul><li>Specifically trained for code generation and understanding</li><li>Fill-in-the-middle (FIM) support for code completion</li><li>100K context window (larger than base Llama 2)</li><li>Instruct variants for conversational coding</li></ul><p><strong>Limitations:</strong></p><ul><li>Based on older Llama 2 architecture</li><li>Largely superseded by Qwen2.5-Coder and newer models</li><li>Smaller community momentum</li></ul><h3 id="starcoder2-bigcode" tabindex="-1">StarCoder2 (BigCode) <a class="header-anchor" href="#starcoder2-bigcode" aria-label="Permalink to &quot;StarCoder2 (BigCode)&quot;">​</a></h3><p>Open-source model trained exclusively on code:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> starcoder2:15b</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> starcoder2:7b</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> starcoder2:3b</span></span></code></pre></div><p><strong>Strengths:</strong></p><ul><li>Trained on The Stack v2 (massive code dataset)</li><li>Strong code completion (FIM native)</li><li>Available in 3B, 7B, 15B sizes</li><li>Good for IDE-style code completion</li></ul><p><strong>Limitations:</strong></p><ul><li>16K context (much smaller than alternatives)</li><li>Less capable at instruction following</li><li>Better suited for completion than conversation</li><li>Not ideal for agentic tool use</li></ul><h3 id="mistral-mistral-ai" tabindex="-1">Mistral (Mistral AI) <a class="header-anchor" href="#mistral-mistral-ai" aria-label="Permalink to &quot;Mistral (Mistral AI)&quot;">​</a></h3><p>Mistral offers competitive open-source models:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> mistral:7b</span><span style="color:#6C7086;font-style:italic;">         # Mistral 7B</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> mistral-nemo:12b</span><span style="color:#6C7086;font-style:italic;">   # Nemo 12B</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> mixtral:8x7b</span><span style="color:#6C7086;font-style:italic;">       # Mixtral MoE</span></span></code></pre></div><p><strong>Strengths:</strong></p><ul><li>Efficient architectures (sliding window attention)</li><li>Mixtral pioneered open-source MoE models</li><li>Good multilingual support</li><li>Solid instruction following</li></ul><hr><h2 id="local-inference-engines" tabindex="-1">Local Inference Engines <a class="header-anchor" href="#local-inference-engines" aria-label="Permalink to &quot;Local Inference Engines&quot;">​</a></h2><h3 id="ollama" tabindex="-1">Ollama <a class="header-anchor" href="#ollama" aria-label="Permalink to &quot;Ollama&quot;">​</a></h3><p>The most popular way for coding agents to run local models:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install Ollama</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -fsSL</span><span style="color:#A6E3A1;"> https://ollama.ai/install.sh</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> sh</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Pull and run a model</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> qwen2.5-coder:32b</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> run</span><span style="color:#A6E3A1;"> qwen2.5-coder:32b</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Ollama exposes an OpenAI-compatible API</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> http://localhost:11434/v1/chat/completions</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -H</span><span style="color:#A6E3A1;"> &quot;Content-Type: application/json&quot;</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -d</span><span style="color:#A6E3A1;"> &#39;{</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;model&quot;: &quot;qwen2.5-coder:32b&quot;,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;messages&quot;: [</span></span>
<span class="line"><span style="color:#A6E3A1;">      {&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;Write a binary search in Python&quot;}</span></span>
<span class="line"><span style="color:#A6E3A1;">    ]</span></span>
<span class="line"><span style="color:#A6E3A1;">  }&#39;</span></span></code></pre></div><p><strong>Why agents love Ollama:</strong></p><ul><li><strong>OpenAI-compatible API</strong> — Works with any agent that supports custom endpoints</li><li><strong>Easy installation</strong> — Single command setup on Mac, Linux, Windows</li><li><strong>Model management</strong> — Pull, run, and manage models like Docker images</li><li><strong>GPU acceleration</strong> — Automatic CUDA/Metal/ROCm detection</li><li><strong>Multiple models</strong> — Run different models on the same server</li><li><strong>No API keys</strong> — Completely local, no authentication needed</li></ul><p><strong>Agent integration examples:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Codex CLI with Ollama</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> OPENAI_BASE_URL</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;http://localhost:11434/v1&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> OPENAI_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;ollama&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">codex</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> qwen2.5-coder:32b</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Aider with Ollama (via LiteLLM)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">aider</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> ollama/qwen2.5-coder:32b</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Goose with Ollama</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> GOOSE_PROVIDER</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">ollama</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> GOOSE_MODEL</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">qwen2.5-coder:32b</span></span></code></pre></div><h3 id="vllm" tabindex="-1">vLLM <a class="header-anchor" href="#vllm" aria-label="Permalink to &quot;vLLM&quot;">​</a></h3><p>High-performance inference engine for production deployments:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install vLLM</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">pip</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> vllm</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Start server</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">python</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> vllm.entrypoints.openai.api_server</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --model</span><span style="color:#A6E3A1;"> Qwen/Qwen2.5-Coder-32B-Instruct</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --tensor-parallel-size</span><span style="color:#FAB387;"> 2</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --max-model-len</span><span style="color:#FAB387;"> 32768</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --port</span><span style="color:#FAB387;"> 8000</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># vLLM also exposes an OpenAI-compatible API</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> http://localhost:8000/v1/chat/completions</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    -H</span><span style="color:#A6E3A1;"> &quot;Content-Type: application/json&quot;</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    -d</span><span style="color:#A6E3A1;"> &#39;{&quot;model&quot;: &quot;Qwen/Qwen2.5-Coder-32B-Instruct&quot;, &quot;messages&quot;: [...]}&#39;</span></span></code></pre></div><p><strong>Advantages over Ollama:</strong></p><ul><li><strong>Higher throughput</strong> — Optimized for concurrent requests</li><li><strong>PagedAttention</strong> — More efficient memory management</li><li><strong>Tensor parallelism</strong> — Easy multi-GPU scaling</li><li><strong>Continuous batching</strong> — Better utilization under load</li><li><strong>Speculative decoding</strong> — Faster generation with draft models</li></ul><p><strong>When to use vLLM over Ollama:</strong></p><ul><li>Multiple users sharing the same model</li><li>Production deployment with SLA requirements</li><li>Need for maximum tokens/second throughput</li><li>Multi-GPU setups</li></ul><h3 id="llama-cpp" tabindex="-1">llama.cpp <a class="header-anchor" href="#llama-cpp" aria-label="Permalink to &quot;llama.cpp&quot;">​</a></h3><p>The most efficient option for running models on consumer hardware:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Build llama.cpp</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> clone</span><span style="color:#A6E3A1;"> https://github.com/ggerganov/llama.cpp</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> llama.cpp</span><span style="color:#9399B2;"> &amp;&amp;</span><span style="color:#89B4FA;font-style:italic;"> make</span><span style="color:#A6E3A1;"> -j</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run a server (OpenAI-compatible)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">./llama-server</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    -m</span><span style="color:#A6E3A1;"> models/qwen2.5-coder-32b-q4_k_m.gguf</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --port</span><span style="color:#FAB387;"> 8080</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --n-gpu-layers</span><span style="color:#FAB387;"> 35</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    --ctx-size</span><span style="color:#FAB387;"> 32768</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Use with any OpenAI-compatible agent</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> OPENAI_BASE_URL</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;http://localhost:8080/v1&quot;</span></span></code></pre></div><p><strong>Why llama.cpp matters:</strong></p><ul><li><strong>CPU inference</strong> — Runs without a GPU (slower but works)</li><li><strong>Quantization</strong> — Q4/Q5/Q8 quantized models use 2-4x less memory</li><li><strong>Metal acceleration</strong> — Excellent on Apple Silicon Macs</li><li><strong>GGUF format</strong> — Universal model format, widely available</li><li><strong>Minimal dependencies</strong> — Pure C/C++, no Python runtime needed</li></ul><h3 id="comparison-of-inference-engines" tabindex="-1">Comparison of Inference Engines <a class="header-anchor" href="#comparison-of-inference-engines" aria-label="Permalink to &quot;Comparison of Inference Engines&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Ollama</th><th>vLLM</th><th>llama.cpp</th></tr></thead><tbody><tr><td><strong>Setup difficulty</strong></td><td>Very easy</td><td>Moderate</td><td>Moderate</td></tr><tr><td><strong>OpenAI compat API</strong></td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>GPU support</strong></td><td>CUDA, Metal, ROCm</td><td>CUDA</td><td>CUDA, Metal, ROCm, Vulkan</td></tr><tr><td><strong>CPU inference</strong></td><td>✅</td><td>❌</td><td>✅ (optimized)</td></tr><tr><td><strong>Quantization</strong></td><td>✅ (GGUF)</td><td>✅ (GPTQ, AWQ)</td><td>✅ (GGUF, native)</td></tr><tr><td><strong>Multi-GPU</strong></td><td>✅</td><td>✅ (best)</td><td>✅</td></tr><tr><td><strong>Throughput</strong></td><td>Good</td><td>Best</td><td>Good</td></tr><tr><td><strong>Memory efficiency</strong></td><td>Good</td><td>Best</td><td>Good</td></tr><tr><td><strong>Model management</strong></td><td>Built-in</td><td>Manual</td><td>Manual</td></tr><tr><td><strong>Best for</strong></td><td>Development</td><td>Production</td><td>Consumer hardware</td></tr></tbody></table><hr><h2 id="performance-vs-cloud-models" tabindex="-1">Performance vs. Cloud Models <a class="header-anchor" href="#performance-vs-cloud-models" aria-label="Permalink to &quot;Performance vs. Cloud Models&quot;">​</a></h2><h3 id="coding-benchmark-comparison" tabindex="-1">Coding Benchmark Comparison <a class="header-anchor" href="#coding-benchmark-comparison" aria-label="Permalink to &quot;Coding Benchmark Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Size</th><th>HumanEval</th><th>MBPP</th><th>SWE-bench Verified</th></tr></thead><tbody><tr><td><strong>Claude Sonnet 4.6</strong></td><td>Cloud</td><td>~92%</td><td>~88%</td><td>~55%</td></tr><tr><td><strong>GPT-4.1</strong></td><td>Cloud</td><td>~90%</td><td>~87%</td><td>~54%</td></tr><tr><td><strong>Gemini 2.5 Pro</strong></td><td>Cloud</td><td>~91%</td><td>~87%</td><td>~53%</td></tr><tr><td><strong>Qwen2.5-Coder-32B</strong></td><td>32B</td><td>~93%</td><td>~84%</td><td>~25%</td></tr><tr><td><strong>DeepSeek-R1-Distill-70B</strong></td><td>70B</td><td>~85%</td><td>~82%</td><td>~28%</td></tr><tr><td><strong>Llama 3.3-70B</strong></td><td>70B</td><td>~81%</td><td>~82%</td><td>~22%</td></tr><tr><td><strong>Qwen2.5-Coder-7B</strong></td><td>7B</td><td>~82%</td><td>~76%</td><td>~12%</td></tr><tr><td><strong>CodeLlama-34B</strong></td><td>34B</td><td>~68%</td><td>~73%</td><td>~15%</td></tr></tbody></table><h3 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h3><ol><li><strong>Simple code generation</strong> — Local models are competitive (HumanEval/MBPP)</li><li><strong>Complex multi-step tasks</strong> — Cloud models still dominate (SWE-bench)</li><li><strong>Sweet spot</strong> — Qwen2.5-Coder-32B offers the best local coding quality</li><li><strong>Function calling</strong> — Cloud models are significantly more reliable</li><li><strong>Long context</strong> — Cloud models handle 1M tokens; local models often struggle &gt;32K</li></ol><h3 id="speed-comparison" tabindex="-1">Speed Comparison <a class="header-anchor" href="#speed-comparison" aria-label="Permalink to &quot;Speed Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Hardware</th><th>Tokens/sec</th><th>Latency (first token)</th></tr></thead><tbody><tr><td>Claude Sonnet 4.6</td><td>Cloud</td><td>~80 t/s</td><td>~500ms</td></tr><tr><td>GPT-4.1</td><td>Cloud</td><td>~70 t/s</td><td>~300ms</td></tr><tr><td>Qwen2.5-Coder-32B Q4</td><td>RTX 4090</td><td>~25 t/s</td><td>~200ms</td></tr><tr><td>Qwen2.5-Coder-32B Q4</td><td>M3 Max 64GB</td><td>~20 t/s</td><td>~150ms</td></tr><tr><td>Qwen2.5-Coder-7B Q4</td><td>RTX 3060 12GB</td><td>~40 t/s</td><td>~100ms</td></tr><tr><td>Llama-3.3-70B Q4</td><td>2x RTX 4090</td><td>~15 t/s</td><td>~500ms</td></tr><tr><td>Qwen2.5-Coder-7B Q4</td><td>CPU (M3 Pro)</td><td>~8 t/s</td><td>~2s</td></tr></tbody></table><hr><h2 id="how-agents-support-local-models" tabindex="-1">How Agents Support Local Models <a class="header-anchor" href="#how-agents-support-local-models" aria-label="Permalink to &quot;How Agents Support Local Models&quot;">​</a></h2><h3 id="pattern-1-custom-openai-endpoint" tabindex="-1">Pattern 1: Custom OpenAI Endpoint <a class="header-anchor" href="#pattern-1-custom-openai-endpoint" aria-label="Permalink to &quot;Pattern 1: Custom OpenAI Endpoint&quot;">​</a></h3><p>Most agents that support OpenAI can also support local models via endpoint override:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Generic pattern for any OpenAI-compatible agent</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> OPENAI_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;not-needed&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> OPENAI_BASE_URL</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;http://localhost:11434/v1&quot;</span></span></code></pre></div><h3 id="pattern-2-litellm-integration" tabindex="-1">Pattern 2: LiteLLM Integration <a class="header-anchor" href="#pattern-2-litellm-integration" aria-label="Permalink to &quot;Pattern 2: LiteLLM Integration&quot;">​</a></h3><p>Agents using LiteLLM get local model support automatically:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># LiteLLM supports Ollama natively</span></span>
<span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> litellm</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> litellm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">completion</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;ollama/qwen2.5-coder:32b&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    messages</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">[{</span><span style="color:#A6E3A1;">&quot;role&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;content&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Fix this bug...&quot;</span><span style="color:#9399B2;">}],</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    api_base</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;http://localhost:11434&quot;</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span></code></pre></div><h3 id="pattern-3-native-ollama-provider" tabindex="-1">Pattern 3: Native Ollama Provider <a class="header-anchor" href="#pattern-3-native-ollama-provider" aria-label="Permalink to &quot;Pattern 3: Native Ollama Provider&quot;">​</a></h3><p>Some agents implement Ollama as a first-class provider:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Goose&#39;s Ollama integration</span></span>
<span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> OllamaProvider</span><span style="color:#CBA6F7;"> struct</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    BaseURL </span><span style="color:#CBA6F7;">string</span></span>
<span class="line"><span style="color:#CDD6F4;">    Model   </span><span style="color:#CBA6F7;">string</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#9399B2;"> (</span><span style="color:#EBA0AC;font-style:italic;">p </span><span style="color:#94E2D5;">*</span><span style="color:#F9E2AF;font-style:italic;">OllamaProvider</span><span style="color:#9399B2;">)</span><span style="color:#89B4FA;font-style:italic;"> Complete</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">messages</span><span style="color:#9399B2;"> []</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> (</span><span style="color:#94E2D5;">*</span><span style="color:#F9E2AF;font-style:italic;">Response</span><span style="color:#9399B2;">,</span><span style="color:#CBA6F7;"> error</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Uses OpenAI-compatible API at localhost:11434</span></span>
<span class="line"><span style="color:#CDD6F4;">    client </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> openai</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">NewClient</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">openai</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">ClientConfig</span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">        BaseURL</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> p</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">BaseURL </span><span style="color:#94E2D5;">+</span><span style="color:#A6E3A1;"> &quot;/v1&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    })</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">ChatCompletion</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="agent-specific-local-model-support" tabindex="-1">Agent-Specific Local Model Support <a class="header-anchor" href="#agent-specific-local-model-support" aria-label="Permalink to &quot;Agent-Specific Local Model Support&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Local Support</th><th>How</th></tr></thead><tbody><tr><td><strong>Aider</strong></td><td>✅</td><td>LiteLLM → Ollama</td></tr><tr><td><strong>Codex CLI</strong></td><td>✅</td><td>Custom endpoint in TOML config</td></tr><tr><td><strong>Goose</strong></td><td>✅</td><td>Native Ollama + LM Studio + Docker Model Runner</td></tr><tr><td><strong>OpenHands</strong></td><td>✅</td><td>LiteLLM → Ollama</td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>✅</td><td>LiteLLM → Ollama</td></tr><tr><td><strong>OpenCode</strong></td><td>⚠️</td><td>Via OpenAI-compatible endpoint</td></tr><tr><td><strong>ForgeCode</strong></td><td>⚠️</td><td>Via OpenAI-compatible endpoint</td></tr><tr><td><strong>Claude Code</strong></td><td>❌</td><td>Anthropic only</td></tr><tr><td><strong>Gemini CLI</strong></td><td>❌</td><td>Google only</td></tr></tbody></table><hr><h2 id="practical-setup-guide" tabindex="-1">Practical Setup Guide <a class="header-anchor" href="#practical-setup-guide" aria-label="Permalink to &quot;Practical Setup Guide&quot;">​</a></h2><h3 id="recommended-local-model-for-coding-agents" tabindex="-1">Recommended Local Model for Coding Agents <a class="header-anchor" href="#recommended-local-model-for-coding-agents" aria-label="Permalink to &quot;Recommended Local Model for Coding Agents&quot;">​</a></h3><p>For the best local coding experience, use <strong>Qwen2.5-Coder-32B</strong> on hardware with ≥24GB VRAM (or ≥48GB unified memory on Apple Silicon):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Step 1: Install Ollama</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -fsSL</span><span style="color:#A6E3A1;"> https://ollama.ai/install.sh</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> sh</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Step 2: Pull the model</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ollama</span><span style="color:#A6E3A1;"> pull</span><span style="color:#A6E3A1;"> qwen2.5-coder:32b</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Step 3: Verify it works</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> http://localhost:11434/v1/chat/completions</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -H</span><span style="color:#A6E3A1;"> &quot;Content-Type: application/json&quot;</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -d</span><span style="color:#A6E3A1;"> &#39;{</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;model&quot;: &quot;qwen2.5-coder:32b&quot;,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;messages&quot;: [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;Write FizzBuzz in Rust&quot;}]</span></span>
<span class="line"><span style="color:#A6E3A1;">  }&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Step 4: Configure your agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># For Aider:</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">aider</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> ollama/qwen2.5-coder:32b</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># For Codex CLI:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Add to ~/.codex/config.toml:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># [providers.ollama]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># base_url = &quot;http://localhost:11434/v1&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># model = &quot;qwen2.5-coder:32b&quot;</span></span></code></pre></div><h3 id="if-you-have-limited-hardware" tabindex="-1">If You Have Limited Hardware <a class="header-anchor" href="#if-you-have-limited-hardware" aria-label="Permalink to &quot;If You Have Limited Hardware&quot;">​</a></h3><table tabindex="0"><thead><tr><th>VRAM</th><th>Recommended Model</th><th>Quality</th></tr></thead><tbody><tr><td><strong>48GB+</strong></td><td>Qwen2.5-Coder-32B (full)</td><td>Excellent</td></tr><tr><td><strong>24GB</strong></td><td>Qwen2.5-Coder-32B Q4</td><td>Very good</td></tr><tr><td><strong>16GB</strong></td><td>Qwen2.5-Coder-14B Q4</td><td>Good</td></tr><tr><td><strong>8GB</strong></td><td>Qwen2.5-Coder-7B Q4</td><td>Decent</td></tr><tr><td><strong>4GB</strong></td><td>Qwen2.5-Coder-1.5B Q4</td><td>Limited</td></tr><tr><td><strong>CPU only</strong></td><td>Qwen2.5-Coder-7B Q4</td><td>Slow but works</td></tr></tbody></table><h3 id="apple-silicon-recommendations" tabindex="-1">Apple Silicon Recommendations <a class="header-anchor" href="#apple-silicon-recommendations" aria-label="Permalink to &quot;Apple Silicon Recommendations&quot;">​</a></h3><p>Apple Silicon Macs are excellent for local model inference due to unified memory:</p><table tabindex="0"><thead><tr><th>Mac</th><th>Unified Memory</th><th>Best Model</th><th>Quality</th></tr></thead><tbody><tr><td>M3/M4 Pro (18GB)</td><td>18GB</td><td>Qwen2.5-Coder-14B Q4</td><td>Good</td></tr><tr><td>M3/M4 Pro (36GB)</td><td>36GB</td><td>Qwen2.5-Coder-32B Q4</td><td>Very good</td></tr><tr><td>M3/M4 Max (64GB)</td><td>64GB</td><td>Qwen2.5-Coder-32B FP16</td><td>Excellent</td></tr><tr><td>M3/M4 Max (128GB)</td><td>128GB</td><td>Llama-3.3-70B Q4</td><td>Strong</td></tr><tr><td>M2/M3 Ultra</td><td>192GB</td><td>DeepSeek-R1-Distill-70B FP16</td><td>Very strong</td></tr></tbody></table><hr><h2 id="trade-offs-local-vs-cloud" tabindex="-1">Trade-offs: Local vs. Cloud <a class="header-anchor" href="#trade-offs-local-vs-cloud" aria-label="Permalink to &quot;Trade-offs: Local vs. Cloud&quot;">​</a></h2><h3 id="when-local-models-win" tabindex="-1">When Local Models Win <a class="header-anchor" href="#when-local-models-win" aria-label="Permalink to &quot;When Local Models Win&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Why Local is Better</th></tr></thead><tbody><tr><td><strong>Privacy-critical code</strong></td><td>Code never leaves your machine</td></tr><tr><td><strong>No internet access</strong></td><td>Air-gapped development environments</td></tr><tr><td><strong>Unlimited usage</strong></td><td>No per-token costs after hardware investment</td></tr><tr><td><strong>Low latency (simple tasks)</strong></td><td>No network round-trip, instant first token</td></tr><tr><td><strong>Rate limit freedom</strong></td><td>No RPM or TPM limits</td></tr><tr><td><strong>Offline development</strong></td><td>Works on planes, in remote areas</td></tr><tr><td><strong>Fine-tuning</strong></td><td>Can train on proprietary codebases</td></tr></tbody></table><h3 id="when-cloud-models-win" tabindex="-1">When Cloud Models Win <a class="header-anchor" href="#when-cloud-models-win" aria-label="Permalink to &quot;When Cloud Models Win&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Why Cloud is Better</th></tr></thead><tbody><tr><td><strong>Complex reasoning</strong></td><td>GPT-4/Claude/Gemini are 2-3x better on SWE-bench</td></tr><tr><td><strong>Long context</strong></td><td>Cloud models handle 1M tokens vs. 32-128K local</td></tr><tr><td><strong>Function calling</strong></td><td>Cloud models are much more reliable for tool use</td></tr><tr><td><strong>Multi-step tasks</strong></td><td>Cloud models maintain coherence over many turns</td></tr><tr><td><strong>Cost (low volume)</strong></td><td>$10/month API &lt; $1000+ GPU investment</td></tr><tr><td><strong>Latest models</strong></td><td>Cloud providers update models regularly</td></tr><tr><td><strong>No hardware needed</strong></td><td>Any laptop can use cloud APIs</td></tr></tbody></table><h3 id="hybrid-approach" tabindex="-1">Hybrid Approach <a class="header-anchor" href="#hybrid-approach" aria-label="Permalink to &quot;Hybrid Approach&quot;">​</a></h3><p>The most practical strategy for many users:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Use local models for simple tasks, cloud for complex ones</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> select_provider</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">task</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> task</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">estimated_complexity </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;simple&quot;</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> OllamaProvider</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;qwen2.5-coder:32b&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    elif</span><span style="color:#CDD6F4;"> task</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">estimated_complexity </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;moderate&quot;</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> DeepSeekProvider</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;deepseek-chat&quot;</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # Cheap cloud</span></span>
<span class="line"><span style="color:#CBA6F7;">    else</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> AnthropicProvider</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;claude-sonnet-4-6&quot;</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # Best quality</span></span></code></pre></div><hr><h2 id="future-directions" tabindex="-1">Future Directions <a class="header-anchor" href="#future-directions" aria-label="Permalink to &quot;Future Directions&quot;">​</a></h2><h3 id="trends-to-watch" tabindex="-1">Trends to Watch <a class="header-anchor" href="#trends-to-watch" aria-label="Permalink to &quot;Trends to Watch&quot;">​</a></h3><ol><li><strong>Rapidly improving quality</strong> — Open models are closing the gap with cloud models</li><li><strong>Smaller, better models</strong> — The 7-14B range is becoming increasingly capable</li><li><strong>Better function calling</strong> — Critical for agentic use cases</li><li><strong>Longer context</strong> — 128K is standard, 1M coming</li><li><strong>Specialized code models</strong> — Models trained specifically for agentic coding</li><li><strong>Hardware improvements</strong> — NPUs, dedicated AI accelerators on laptops</li><li><strong>Model merging</strong> — Community techniques for combining model strengths</li></ol><h3 id="the-path-to-local-first-agents" tabindex="-1">The Path to Local-First Agents <a class="header-anchor" href="#the-path-to-local-first-agents" aria-label="Permalink to &quot;The Path to Local-First Agents&quot;">​</a></h3><p>As open models improve, we may see a shift toward local-first agents that only fall back to cloud providers for the hardest tasks. The economic equation tilts further toward local as:</p><ul><li>Model quality at 32B approaches cloud frontier</li><li>Consumer GPUs get more VRAM (RTX 5090: 32GB)</li><li>Apple Silicon continues to increase unified memory</li><li>Quantization techniques improve quality at lower precision</li></ul><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./deepseek.html">DeepSeek</a> — Open-weight frontier model with API access</li><li><a href="./litellm.html">LiteLLM</a> — Unified interface for local and cloud models</li><li><a href="./pricing-and-cost.html">Pricing and Cost</a> — Cost comparison including local hosting</li><li><a href="./model-routing.html">Model Routing</a> — Routing between local and cloud models</li></ul>`,121)])])}const u=s(e,[["render",o]]);export{h as __pageData,u as default};
